class ProductGrid extends StatelessWidget {
  final List<Product> products;
  const ProductGrid({required this.products});

  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(
      builder: (context, constraints) {
        final columns = constraints.maxWidth < 600 ? 2 : 3;
        return GridView.builder(
          gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
            crossAxisCount: columns,
            crossAxisSpacing: 8,
            mainAxisSpacing: 8,
          ),
          itemCount: products.length,
          itemBuilder: (context, index) {
            final product = products[index];
            return Card(
              child: Padding(
                padding: EdgeInsets.all(12),
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Text(product.name, style: Theme.of(context).textTheme.titleMedium),
                    SizedBox(height: 8),
                    Text('\$${product.price.toStringAsFixed(2)}'),
                  ],
                ),
              ),
            );
          },
        );
      },
    );
  }
}

class CartModel extends ChangeNotifier {
  final Map<String, CartItem> _items = {};
  Map<String, CartItem> get items => Map.unmodifiable(_items);

  double get totalPrice => _items.values
      .fold(0, (sum, item) => sum + item.price * item.quantity);

  int get itemCount => _items.values
      .fold(0, (sum, item) => sum + item.quantity);

  void addItem(String id, String name, double price) {
    if (_items.containsKey(id)) {
      _items[id] = _items[id]!.copyWith(quantity: _items[id]!.quantity + 1);
    } else {
      _items[id] = CartItem(id: id, name: name, price: price, quantity: 1);
    }
    notifyListeners();
  }

  void removeItem(String id) {
    _items.remove(id);
    notifyListeners();
  }

  void updateQuantity(String id, int quantity) {
    if (quantity <= 0) { removeItem(id); return; }
    if (_items.containsKey(id)) {
      _items[id] = _items[id]!.copyWith(quantity: quantity);
      notifyListeners();
    }
  }
}

// Providing:
ChangeNotifierProvider(create: (_) => CartModel(), child: MyApp())

// Selective consumption (only rebuilds when totalPrice changes):
Selector<CartModel, double>(
  selector: (_, cart) => cart.totalPrice,
  builder: (_, total, __) => Text('Total: \$${total.toStringAsFixed(2)}'),
)

class AuthInterceptor extends Interceptor {
  final FlutterSecureStorage _storage;
  final Dio _refreshDio; // separate Dio instance to avoid interceptor loop
  Completer<String>? _refreshCompleter;

  AuthInterceptor(this._storage, this._refreshDio);

  @override
  void onRequest(RequestOptions options, RequestInterceptorHandler handler) async {
    final token = await _storage.read(key: 'access_token');
    if (token != null) {
      options.headers['Authorization'] = 'Bearer $token';
    }
    handler.next(options);
  }

  @override
  void onError(DioException err, ErrorInterceptorHandler handler) async {
    if (err.response?.statusCode != 401) {
      handler.next(err);
      return;
    }
    try {
      final newToken = await _refreshToken();
      err.requestOptions.headers['Authorization'] = 'Bearer $newToken';
      final response = await _refreshDio.fetch(err.requestOptions);
      handler.resolve(response);
    } catch (e) {
      handler.next(err);
    }
  }

  Future<String> _refreshToken() async {
    if (_refreshCompleter != null) return _refreshCompleter!.future;
    _refreshCompleter = Completer<String>();
    try {
      final refreshToken = await _storage.read(key: 'refresh_token');
      final response = await _refreshDio.post('/auth/refresh',
          data: {'refresh_token': refreshToken});
      final newToken = response.data['access_token'];
      await _storage.write(key: 'access_token', value: newToken);
      _refreshCompleter!.complete(newToken);
      return newToken;
    } catch (e) {
      _refreshCompleter!.completeError(e);
      rethrow;
    } finally {
      _refreshCompleter = null;
    }
  }
}
